import{_ as e,o as a,c as n,a2 as r}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"F17: 籌碼分佈與法人動態分析 - 投資研究員審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/8103_瀚荃/20260425/F17_籌碼分佈與法人動態分析_投資研究員.md","filePath":"審計報告庫/財務審計/8103_瀚荃/20260425/F17_籌碼分佈與法人動態分析_投資研究員.md"}'),l={name:"審計報告庫/財務審計/8103_瀚荃/20260425/F17_籌碼分佈與法人動態分析_投資研究員.md"};function o(i,t,d,s,h,c){return a(),n("div",null,[...t[0]||(t[0]=[r('<h1 id="f17-籌碼分佈與法人動態分析-投資研究員審計報告" tabindex="-1">F17: 籌碼分佈與法人動態分析 - 投資研究員審計報告 <a class="header-anchor" href="#f17-籌碼分佈與法人動態分析-投資研究員審計報告" aria-label="Permalink to &quot;F17: 籌碼分佈與法人動態分析 - 投資研究員審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>外資、投信與自營商的近期買賣超動向為何？千張大戶持股比例是否發生結構性變化？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>外資近20日淨買超+3,242張，持股比從14.09%翻升至25.85%創近期新高，屬外資單邊鎖碼型態。千張大戶佔比50.52%（12週+1.41pp）、400張以上達59.54%（12週+2.31pp），籌碼集中度創3年新高，呈現法人與大戶同步收斂的攻擊態勢。散戶人數暴增56.5%為高位隱憂。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>A（良）</strong></p><p>評級依據：</p><ul><li>外資連續 3 週大舉買超，近 8 週合計淨買超約 +1,869,322 股，方向性合力明確</li><li>千張大戶佔比 50.52% 且持續上升，籌碼高度集中</li><li>投信零持股，不存在「投信結帳壓力」——但同時也缺乏投信背書的成長股認可</li><li>散戶人數暴增（+56.5%）為扣分項，短線籌碼有渙散隱患</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="一、三大法人近期買賣超動向" tabindex="-1">一、三大法人近期買賣超動向 <a class="header-anchor" href="#一、三大法人近期買賣超動向" aria-label="Permalink to &quot;一、三大法人近期買賣超動向&quot;">​</a></h3><p><strong>近8週法人合計進出（股）</strong></p><table tabindex="0"><thead><tr><th>週次</th><th style="text-align:center;">外資</th><th style="text-align:center;">投信</th><th style="text-align:center;">自營商</th><th style="text-align:center;">合計</th></tr></thead><tbody><tr><td>W10-W13</td><td style="text-align:center;">-1,464,806</td><td style="text-align:center;">-311,000</td><td style="text-align:center;">-56,018</td><td style="text-align:center;"><strong>-1,831,824</strong></td></tr><tr><td>W14-W17</td><td style="text-align:center;">+3,283,765</td><td style="text-align:center;">0</td><td style="text-align:center;">+149,581</td><td style="text-align:center;"><strong>+3,433,346</strong></td></tr></tbody></table><p><strong>關鍵轉折</strong>：W10-W13外資連續4週賣超合計約-146萬股，W14起反轉為買超且力度逐週放大，W17單週買超129.8萬股創近期新高。此轉折對應2026年3月營收3.33億元（月增55.3%、年增25.8%）的優異表現及AI電源題材升溫。</p><p><strong>近20日累計</strong>：外資+3,241,691股、投信0股、自營商+150,375股，合計+3,671,201股。4/20單日爆量買超130萬股為近期峰值，後續出現短線獲利了結但趨勢未被破壞。</p><h3 id="二、外資持股水位趨勢" tabindex="-1">二、外資持股水位趨勢 <a class="header-anchor" href="#二、外資持股水位趨勢" aria-label="Permalink to &quot;二、外資持股水位趨勢&quot;">​</a></h3><p>外資持股從2023年7.88%持續攀升至25.85%，3年間增幅達+17.97pp，持股量增加1,405萬股。這種連續增持在台股中型電子股中相當罕見，反映外資對AI連接器題材的長期看好。投信零持股代表缺乏國內法人認可，但同時不存在結帳壓力風險。</p><h3 id="三、千張大戶結構性變化" tabindex="-1">三、千張大戶結構性變化 <a class="header-anchor" href="#三、千張大戶結構性變化" aria-label="Permalink to &quot;三、千張大戶結構性變化&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指標</th><th style="text-align:center;">3年前</th><th style="text-align:center;">最新</th><th style="text-align:center;">變化</th></tr></thead><tbody><tr><td>千張大戶佔比</td><td style="text-align:center;">45.90%</td><td style="text-align:center;">50.52%</td><td style="text-align:center;">+4.62pp</td></tr><tr><td>400張以上佔比</td><td style="text-align:center;">53.18%</td><td style="text-align:center;">59.54%</td><td style="text-align:center;">+6.36pp</td></tr><tr><td>散戶佔比</td><td style="text-align:center;">2.31%</td><td style="text-align:center;">1.93%</td><td style="text-align:center;">-0.38pp</td></tr></tbody></table><p><strong>鎖碼特徵</strong>：外資W14起連續4週買超約+328萬股，同期千張大戶佔比由47.81%升至50.52%（+2.71pp），法人買超與大戶持股同步攀升，呈現「法人鎖碼+大戶收斂」的雙重鎖死特徵。</p><h3 id="四、散戶背離測試" tabindex="-1">四、散戶背離測試 <a class="header-anchor" href="#四、散戶背離測試" aria-label="Permalink to &quot;四、散戶背離測試&quot;">​</a></h3><p>散戶人數雖暴增（+56.5%），但散戶持股佔比下降（-0.28pp/12週），代表新增者多為極小額投資者。千張大戶比例持續上升、法人未撤退，<strong>「派發期」警報尚未觸發</strong>，但散戶人數急速膨脹為必須持續監控的領先指標。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><h3 id="空頭視角-最極端的風險阻力" tabindex="-1">空頭視角：最極端的風險阻力 <a class="header-anchor" href="#空頭視角-最極端的風險阻力" aria-label="Permalink to &quot;空頭視角：最極端的風險阻力&quot;">​</a></h3><ol><li><strong>外資假買真賣的套利風險</strong>：4/20單日買超130萬股後，4/21立即賣超58萬股、4/23再賣47萬股。大買大賣可能隱含區間套利意圖。若買超趨緩轉為持續賣超，股價將失去最主要上攻引擎。</li><li><strong>投信零持股=缺乏成長股認證</strong>：瀚荃完全無投信部位，國內法人對AI題材持續性存疑。一旦外資買盤枯竭，缺乏承接緩衝，股價修正速度可能極快。</li><li><strong>外資持股過高的反噬效應</strong>：外資持股25.85%，若續增至30%以上，將面臨買盤枯竭。當增持動能衰竭，獲利了結將形成強大賣壓。</li></ol><h3 id="物理對策" tabindex="-1">物理對策 <a class="header-anchor" href="#物理對策" aria-label="Permalink to &quot;物理對策&quot;">​</a></h3><ul><li><strong>持續追蹤</strong>：每週外資持股變動（單週減少&gt;1pp啟動警報）</li><li><strong>派發確認信號</strong>：千張大戶佔比連續2週下降+散戶佔比連續2週上升=派發啟動</li><li><strong>投信進場</strong>：視為正面催化劑</li></ul><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ol><li><strong>FinMind TaiwanStockInstitutionalHolding</strong>：調用 <code>institutional 8103 2025-01-01 2026-04-25 --df</code>，取得三大法人逐日買賣超數據</li><li><strong>FinMind TaiwanStockShareholdingSpread</strong>：調用 <code>backer_holding 8103 2025-01-01 2026-04-25 --df</code>，取得 8 週股權分散表數據</li><li><strong>FinMind ForeignInvestment</strong>：調用 <code>holding 8103 2025-01-01 2026-04-25 --df</code>，取得外資持股比例趨勢（14.09% → 25.85%）</li><li><strong>Python 分析腳本</strong>：<code>/tmp/8103_analysis_v2.py</code>，計算近 20 日累計、週合計、12 週變化等指標</li></ol><hr><p><strong>報告產出日期</strong>：2026-04-25 <strong>數據截止日</strong>：2026-04-24（法人買賣超）/ 2026-04-24（外資持股）/ 2026-04-24（股權分散表） <strong>專家身分</strong>：投資研究員（Finance Investment Researcher） <strong>審計協議版本</strong>：v5.1 Protocol-Linked</p>',31)])])}const _=e(l,[["render",o]]);export{p as __pageData,_ as default};
